{
  // Leisure-consumption choice with CES utility.
  // Time endowment T, wage w. Without tax: C = w·(T - ℓ). With tax: C = w·(1 - τ)·(T - ℓ).
  // CES utility:  U(C, ℓ) = [α·C^((σ-1)/σ) + (1-α)·ℓ^((σ-1)/σ)]^(σ/(σ-1)).
  // For σ = 1, U(C, ℓ) = C^α · ℓ^(1-α) (Cobb-Douglas).
  // Optimum at net wage w_n: ℓ* = T / (1 + (α/(1-α))^σ · w_n^(σ-1)).
  const T = 24;
  const w = 10;
  const alpha = 0.5;
  const sigma = sig_l;
  const tauFrac = tau_l / 100;
  const w0 = w;
  const w1 = w * (1 - tauFrac);

  const eps = 1e-9;

  // Utility helpers
  function U(C, ell) {
    const c = Math.max(C, eps), l = Math.max(ell, eps);
    if (Math.abs(sigma - 1) &lt; 1e-6) {
      return Math.pow(c, alpha) * Math.pow(l, 1 - alpha);
    }
    const e = (sigma - 1) / sigma;
    const inner = alpha * Math.pow(c, e) + (1 - alpha) * Math.pow(l, e);
    if (inner &lt;= 0) return 0;
    return Math.pow(inner, 1 / e);
  }

  // Optimum at net wage w_n
  function optimum(w_n) {
    let ell;
    if (Math.abs(sigma - 1) &lt; 1e-6) {
      // Cobb-Douglas: ℓ* = (1-α)·T
      ell = (1 - alpha) * T;
    } else {
      const ratio = Math.pow(alpha / (1 - alpha), sigma) * Math.pow(w_n, sigma - 1);
      ell = T / (1 + ratio);
    }
    const C = w_n * (T - ell);
    return {ell, C};
  }

  // Compensated optimum B: same utility as A, but at slope w₁.
  // For CES, MRS_(C for ℓ) = ((1-α)/α)·(C/ℓ)^(1/σ) = w_n
  // ⇒ C/ℓ = (α·w_n/(1-α))^σ, i.e. C = k·ℓ with k = (α·w_n/(1-α))^σ.
  // Substitute into U(C, ℓ) = U_bar to solve for ℓ on the original indifference curve.
  function compensated(U_bar, w_n) {
    const k = Math.pow(alpha * w_n / (1 - alpha), sigma);
    let ell;
    if (Math.abs(sigma - 1) &lt; 1e-6) {
      // U = (k·ℓ)^α · ℓ^(1-α) = k^α · ℓ
      ell = U_bar / Math.pow(k, alpha);
    } else {
      const e = (sigma - 1) / sigma;
      // U(kℓ, ℓ) = [α·(kℓ)^e + (1-α)·ℓ^e]^(1/e)
      //          = ℓ · [α·k^e + (1-α)]^(1/e)
      const factor = Math.pow(alpha * Math.pow(k, e) + (1 - alpha), 1 / e);
      ell = U_bar / factor;
    }
    const C = k * ell;
    return {ell, C};
  }

  const A = optimum(w0);
  const C_pt = optimum(w1);
  const U_A = U(A.C, A.ell);
  const B = compensated(U_A, w1);

  // Hours worked
  const hoursA = T - A.ell;
  const hoursC = T - C_pt.ell;
  const dHours = hoursC - hoursA;

  // Substitution effect on leisure: A → B (along original indifference curve).
  // Income effect on leisure: B → C (parallel shift to lower indifference curve).
  const subEffect = B.ell - A.ell;
  const incEffect = C_pt.ell - B.ell;

  // Budget lines as endpoint pairs
  const budgetNoTax = [{ell: 0, C: w0 * T}, {ell: T, C: 0}];
  const budgetTax   = [{ell: 0, C: w1 * T}, {ell: T, C: 0}];

  // Indifference curves through A and through C_pt
  function indiffCurve(U_bar) {
    const pts = [];
    const ellGrid = d3.range(0.5, T + 0.01, 0.5);
    for (const ell of ellGrid) {
      // Solve U(C, ell) = U_bar for C numerically (closed-form for CES is tractable):
      // [α·C^e + (1-α)·ell^e]^(1/e) = U_bar
      // ⇒ α·C^e = U_bar^e - (1-α)·ell^e
      // ⇒ C = ((U_bar^e - (1-α)·ell^e) / α)^(1/e)
      let C;
      if (Math.abs(sigma - 1) &lt; 1e-6) {
        // U = C^α · ell^(1-α) = U_bar  ⇒  C = (U_bar / ell^(1-α))^(1/α)
        C = Math.pow(U_bar / Math.pow(Math.max(ell, eps), 1 - alpha), 1 / alpha);
      } else {
        const e = (sigma - 1) / sigma;
        const numerator = Math.pow(U_bar, e) - (1 - alpha) * Math.pow(ell, e);
        if (numerator / alpha &lt;= 0) continue;
        C = Math.pow(numerator / alpha, 1 / e);
      }
      if (isFinite(C) && C &gt; 0 && C &lt; w0 * T * 1.5) pts.push({ell, C});
    }
    return pts;
  }

  const U_C = U(C_pt.C, C_pt.ell);
  const indiffA = indiffCurve(U_A);
  const indiffC = indiffCurve(U_C);

  const Cmax = w0 * T * 1.05;

  return Plot.plot({
    width: 760,
    height: 520,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Roboto, system-ui, sans-serif", color: "#4A5568"},
    x: {label: "Dokolica ℓ →", domain: [0, T], grid: false},
    y: {label: "↑ Potrošnja C", domain: [0, Cmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#CBD5E0"}),

      // Budget lines
      Plot.line(budgetNoTax, {x: "ell", y: "C", stroke: "#2ca02c", strokeWidth: 2.5}),
      Plot.line(budgetTax,   {x: "ell", y: "C", stroke: "#2ca02c", strokeWidth: 2, strokeDasharray: "6,4"}),

      // Indifference curves
      Plot.line(indiffA, {x: "ell", y: "C", stroke: "#1f77b4", strokeWidth: 2}),
      Plot.line(indiffC, {x: "ell", y: "C", stroke: "#C53030", strokeWidth: 2, strokeDasharray: "4,3"}),

      // Substitution-effect arrow (A → B) on the x-axis baseline
      Plot.link(
        [{x1: A.ell, y1: Cmax * 0.06, x2: B.ell, y2: Cmax * 0.06}],
        {x1: "x1", y1: "y1", x2: "x2", y2: "y2",
         stroke: "#805AD5", strokeWidth: 2.5, markerEnd: "arrow"}),
      // Income-effect arrow (B → C) on a separate baseline
      Plot.link(
        [{x1: B.ell, y1: Cmax * 0.02, x2: C_pt.ell, y2: Cmax * 0.02}],
        {x1: "x1", y1: "y1", x2: "x2", y2: "y2",
         stroke: "#D69E2E", strokeWidth: 2.5, markerEnd: "arrow"}),

      // Three optima
      Plot.dot([A], {x: "ell", y: "C", r: 6, fill: "#1f77b4", stroke: "white", strokeWidth: 2}),
      Plot.dot([B], {x: "ell", y: "C", r: 6, fill: "#805AD5", stroke: "white", strokeWidth: 2}),
      Plot.dot([C_pt], {x: "ell", y: "C", r: 6, fill: "#C53030", stroke: "white", strokeWidth: 2}),

      // Drop-lines from optima to x-axis (faded)
      Plot.ruleX([A.ell],    {y1: 0, y2: A.C,    stroke: "#BEE3F8", strokeDasharray: "2,2"}),
      Plot.ruleX([C_pt.ell], {y1: 0, y2: C_pt.C, stroke: "#FED7D7", strokeDasharray: "2,2"}),

      // Labels on the optima
      Plot.text([{ell: A.ell, C: A.C, label: "A (bez poreza)"}],
        {x: "ell", y: "C", text: "label", textAnchor: "start", dx: 8, dy: -10,
         fontSize: 12, fill: "#1f77b4", fontWeight: 600}),
      Plot.text([{ell: B.ell, C: B.C, label: "B (kompenzirani)"}],
        {x: "ell", y: "C", text: "label", textAnchor: "start", dx: 8, dy: -10,
         fontSize: 12, fill: "#805AD5", fontWeight: 600}),
      Plot.text([{ell: C_pt.ell, C: C_pt.C, label: "C (s porezom)"}],
        {x: "ell", y: "C", text: "label", textAnchor: "start", dx: 8, dy: 14,
         fontSize: 12, fill: "#C53030", fontWeight: 600}),

      // Effect labels next to the arrows
      Plot.text([{x: (A.ell + B.ell) / 2, y: Cmax * 0.06,
         label: `Supstitucijski (Δℓ = ${subEffect &gt;= 0 ? "+" : ""}${subEffect.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: -8,
         fontSize: 11, fill: "#553C9A", fontWeight: 600}),
      Plot.text([{x: (B.ell + C_pt.ell) / 2, y: Cmax * 0.02,
         label: `Dohodovni (Δℓ = ${incEffect &gt;= 0 ? "+" : ""}${incEffect.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", textAnchor: "middle", dy: 14,
         fontSize: 11, fill: "#B7791F", fontWeight: 600}),

      // Top readouts
      Plot.text([{x: 0.5, y: Cmax * 0.97,
         label: `Sati rada: ${hoursA.toFixed(1)} → ${hoursC.toFixed(1)}   (Δ = ${dHours &gt;= 0 ? "+" : ""}${dHours.toFixed(2)})`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#2D3748", fontWeight: 700}),
      Plot.text([{x: 0.5, y: Cmax * 0.91,
         label: `σ = ${sigma.toFixed(1)}   |   neto nadnica: ${w0.toFixed(1)} → ${w1.toFixed(2)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 12, fill: "#4A5568", fontWeight: 500})
    ]
  });
}







Kako čitati graf. Vodoravna os je dokolica ℓ, okomita potrošnja C. Zelena puna linija je proračunsko ograničenje bez poreza (C = w·(T − ℓ)), zelena isprekidana s porezom na rad — porez smanjuje nagib jer svaki sat rada donosi manje neto potrošnje. Plava puna krivulja je krivulja indiferencije kroz početni optimum A, crvena isprekidana kroz konačni optimum C. Ljubičasta točka B je hipotetski „kompenzirani” optimum — ono što bi pojedinac izabrao pri novoj nadnici da je istovremeno dobio dohodovnu kompenzaciju koja ga vraća na izvornu razinu korisnosti.
Slutskyjeva dekompozicija. Pomak A → B (ljubičasta strelica) izolira supstitucijski učinak: niža neto nadnica čini sat rada manje vrijednim, pa pojedinac zamjenjuje rad dokolicom (Δℓ raste). Pomak B → C (žuta strelica) je dohodovni učinak: porez osiromašuje pojedinca, a ako je dokolica „normalno dobro”, siromašniji pojedinac troši manje dokolice — odnosno radi više kako bi nadoknadio izgubljeni dohodak. Smjer učinka poreza na zaposlenost ovisi o tome koji od ova dva učinka prevladava.
Što isprobati. (1) Pri σ = 1,0 (Cobb–Douglasova korisnost) supstitucijski i dohodovni učinak točno se poništavaju — broj sati rada uopće se ne mijenja s porezom (Δ = 0). To je referentni neutralni slučaj. (2) Povećajte σ na ~1,8 (potrošnja i dokolica lako se zamjenjuju): supstitucijski učinak nadjačava, broj sati rada opada s porezom — standardni argument protiv visokih marginalnih stopa. (3) Smanjite σ na ~0,3 (potrošač snažno preferira određeni omjer dokolice i potrošnje): dohodovni učinak nadjačava, broj sati rada zapravo raste — empirijska pojava poznata kao unazad savijena krivulja ponude rada koju spominje sljedeći odlomak. Praktična poruka. Kada Mirrleesov model kaže da „optimalna porezna stopa ovisi o ravnoteži supstitucijskog i dohodovnog učinka”, on misli točno na ovu napetost. Smjer i veličina te ravnoteže empirijski je pitanje, što je razlog zašto i danas ne postoji konsenzus o optimalnoj progresivnosti poreza na rad.
Zbog interakcije ova dva učinka, krivulja ponude rada može imati specifičan oblik — pri višim razinama nadnice može prevladati dohodovni učinak te pojedinci biraju više dokolice, što rezultira tzv. unazad savijenom krivuljom ponude rada. Jedan od važnih zaključaka Mirrleesove teorije jest da optimalni porezni sustav ne mora imati ekstremno visoke stope za najbogatije. Razlog je taj što visoke stope mogu značajno smanjiti ekonomske poticaje upravo kod onih koji generiraju najveći dio dohotka.


