Prikaži kod
{
  // Two-period model. Endowment Y in period 1, no income in period 2.
  // Without tax: C2 = (1+r)·(Y − C1).        Optimum chooses C1, C2 to maximise CRRA utility.
  // With tax τ on the return: C2 = (1+r·(1−τ))·(Y − C1).
  // CRRA utility: U = u(C1) + β·u(C2),  with β = 1/(1+ρ),  ρ = 0.04 (subjective discount).
  // Closed-form for CRRA: C2/C1 = [β·(1+r_net)]^σ.
  const Y = 100;
  const Cmax = 130;
  const beta = 1 / 1.04;

  const tauFrac = tau_k / 100;
  const r0 = r;
  const r1 = r * (1 - tauFrac);

  // Optimum given net return r_net and elasticity σ:
  // C2 / C1 = [β·(1 + r_net)]^σ.   Budget: C2 = (1 + r_net)·(Y − C1).
  // ⇒ C1 = Y / (1 + (1 + r_net) / k),  where k = [β·(1 + r_net)]^σ.
  function optimum(r_net) {
    const k = Math.pow(beta * (1 + r_net), sigma);
    const C1 = Y / (1 + (1 + r_net) / k);
    const C2 = (1 + r_net) * (Y - C1);
    return {C1, C2, k};
  }

  const before = optimum(r0);
  const after  = optimum(r1);

  // Budget lines as two-point segments
  const budgetNoTax = [
    {C1: 0, C2: (1 + r0) * Y},
    {C1: Y, C2: 0}
  ];
  const budgetTax = [
    {C1: 0, C2: (1 + r1) * Y},
    {C1: Y, C2: 0}
  ];

  // Indifference curves through the two optima.
  // For CRRA: u(C) = C^(1-1/σ)/(1-1/σ)  (or ln(C) if σ=1).
  // The indifference curve through (C1*, C2*) is the locus where u(C1)+β·u(C2) = constant.
  function indiff(C1opt, C2opt) {
    const eps = 1e-9;
    const uOf = c =&gt; {
      if (Math.abs(sigma - 1) &lt; 1e-6) return Math.log(Math.max(c, eps));
      const e = 1 - 1 / sigma;
      return Math.pow(Math.max(c, eps), e) / e;
    };
    const Ubar = uOf(C1opt) + beta * uOf(C2opt);
    const pts = [];
    const C1grid = d3.range(2, Cmax + 1, 1);
    for (const C1 of C1grid) {
      // Solve uOf(C1) + β·uOf(C2) = Ubar  →  uOf(C2) = (Ubar - uOf(C1))/β
      const target = (Ubar - uOf(C1)) / beta;
      let C2;
      if (Math.abs(sigma - 1) &lt; 1e-6) {
        C2 = Math.exp(target);
      } else {
        const e = 1 - 1 / sigma;
        const arg = target * e;
        if (arg &lt;= 0) continue;
        C2 = Math.pow(arg, 1 / e);
      }
      if (isFinite(C2) && C2 &gt; 0 && C2 &lt; Cmax * 1.5) pts.push({C1, C2});
    }
    return pts;
  }

  const indiffBefore = indiff(before.C1, before.C2);
  const indiffAfter  = indiff(after.C1,  after.C2);

  // Welfare change as a percentage of "before" utility (qualitative readout)
  const dC1 = after.C1 - before.C1;
  const dC2 = after.C2 - before.C2;

  return Plot.plot({
    width: 760,
    height: 520,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Roboto, system-ui, sans-serif", color: "#4A5568"},
    x: {label: "Sadašnja potrošnja C₁ →", domain: [0, Cmax], grid: false},
    y: {label: "↑ Buduća potrošnja C₂",   domain: [0, Cmax], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#CBD5E0"}),

      // Budget line — no tax
      Plot.line(budgetNoTax, {x: "C1", y: "C2", stroke: "#2ca02c", strokeWidth: 2.5}),
      // Budget line — with tax
      Plot.line(budgetTax,   {x: "C1", y: "C2", stroke: "#2ca02c", strokeWidth: 2, strokeDasharray: "6,4"}),

      // Indifference curves
      Plot.line(indiffBefore, {x: "C1", y: "C2", stroke: "#1f77b4", strokeWidth: 2}),
      Plot.line(indiffAfter,  {x: "C1", y: "C2", stroke: "#C53030", strokeWidth: 2, strokeDasharray: "4,3"}),

      // Endowment point
      Plot.dot([{C1: Y, C2: 0}], {x: "C1", y: "C2", r: 4, fill: "#4A5568", stroke: "white", strokeWidth: 1.5}),

      // Optima
      Plot.dot([before], {x: "C1", y: "C2", r: 6, fill: "#1f77b4", stroke: "white", strokeWidth: 2}),
      Plot.dot([after],  {x: "C1", y: "C2", r: 6, fill: "#C53030", stroke: "white", strokeWidth: 2}),

      // Drop-lines for both optima
      Plot.ruleX([before.C1], {y1: 0, y2: before.C2, stroke: "#BEE3F8", strokeDasharray: "2,2"}),
      Plot.ruleY([before.C2], {x1: 0, x2: before.C1, stroke: "#BEE3F8", strokeDasharray: "2,2"}),
      Plot.ruleX([after.C1],  {y1: 0, y2: after.C2,  stroke: "#FED7D7", strokeDasharray: "2,2"}),
      Plot.ruleY([after.C2],  {x1: 0, x2: after.C1,  stroke: "#FED7D7", strokeDasharray: "2,2"}),

      // Labels on optima
      Plot.text([{C1: before.C1, C2: before.C2, label: "Bez poreza"}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 8, dy: -10,
         fontSize: 12, fill: "#1f77b4", fontWeight: 600}),
      Plot.text([{C1: after.C1, C2: after.C2, label: "S porezom"}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 8, dy: 14,
         fontSize: 12, fill: "#C53030", fontWeight: 600}),

      // Endowment label
      Plot.text([{C1: Y, C2: 0, label: `Y = ${Y}`}],
        {x: "C1", y: "C2", text: "label", textAnchor: "start", dx: 6, dy: -8,
         fontSize: 11, fill: "#4A5568"}),

      // Top readouts
      Plot.text([{x: 2, y: Cmax * 0.97,
         label: `Štednja s = Y − C₁:  ${(Y - before.C1).toFixed(1)}  →  ${(Y - after.C1).toFixed(1)}  (Δ = ${(dC1 &lt; 0 ? "+" : "−")}${Math.abs(dC1).toFixed(1)})`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#553C9A", fontWeight: 700}),
      Plot.text([{x: 2, y: Cmax * 0.91,
         label: `Neto prinos: ${(r0 * 100).toFixed(1)} %  →  ${(r1 * 100).toFixed(2)} %    |    σ = ${sigma.toFixed(1)}`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 12, fill: "#4A5568", fontWeight: 500})
    ]
  });
}







Kako čitati graf. Vodoravna os je sadašnja potrošnja C₁, okomita buduća potrošnja C₂. Zelena puna linija je proračunska linija bez poreza, zelena isprekidana s porezom na prinos — ona se zakreće oko točke darivanja Y jer porez smanjuje neto kamatnu stopu. Plava puna krivulja je krivulja indiferencije kroz početni optimum, crvena isprekidana kroz novi optimum. Plava točka je optimum bez poreza, crvena s porezom. U vrhu se ispisuje promjena štednje (s = Y − C₁).
Što isprobati. (1) Pri σ = 1,0 (logaritamska korisnost — supstitucijski i dohodovni učinak približno se poništavaju) i poreznoj stopi od 25 %: optimum se neznatno mijenja, odnosno štednja ostaje gotovo ista. (2) Povećajte σ na ~1,8 (potrošač spreman lako supstituirati potrošnju kroz vrijeme): povećanje poreza značajno smanjuje štednju — supstitucijski učinak nadjačava dohodovni. Ovo je teorijski temelj argumenata Atkinsona i Stiglitza protiv visokih poreza na kapital u sustavima s razvijenim porezom na dohodak. (3) Smanjite σ na ~0,3 (potrošač snažno preferira ravnomjernu potrošnju): porez smanjuje neto prinos, ali pojedinac pojačava štednju kako bi održao buduću razinu potrošnje — dohodovni učinak nadjačava. Praktična poruka. Smjer učinka oporezivanja kapitala na štednju nije jednoznačan; ovisi o elastičnosti intertemporalne supstitucije σ — empirijskom parametru koji teorija optimalnog oporezivanja (atkinson1980?) pokušava izmjeriti, ali oko čije vrijednosti i danas ne postoji znanstveni konsenzus.
Atkinson–Stiglitz teorem (atkinson1980?) — Atkinson i Stiglitz analizirali su pitanje treba li različite vrste potrošnje oporezivati različitim stopama. Njihov ključni rezultat glasi: ako je porez na dohodak optimalno dizajniran, tada diferencirano oporezivanje potrošnje nije potrebno. Drugim riječima, nema potrebe dodatno oporezivati određene proizvode višim ili nižim stopama ako se redistribucija već učinkovito provodi kroz porez na dohodak. Ovaj rezultat ima važne implikacije za dizajn sustava PDV-a. Teorijski, optimalan sustav bi imao jedinstvenu stopu PDV-a, bez izuzetaka. Međutim, u praksi gotovo sve zemlje koriste snižene stope za osnovna dobra, što pokazuje da politički i socijalni ciljevi često nadjačavaju teorijsku optimalnost.
Progresivno oporezivanje i teorija žrtve — progresivno oporezivanje podrazumijeva sustav u kojem prosječna porezna stopa raste s razinom dohotka. Temeljna ekonomska logika takvog sustava proizlazi iz ideje opadajuće granične korisnosti dohotka. Na toj osnovi razvijena je teorija žrtve, koja pokušava normativno opravdati raspodjelu poreznog tereta. Postoje tri varijante: jednaka apsolutna žrtva (svi porezni obveznici trebaju izgubiti isti iznos korisnosti), jednaka proporcionalna žrtva (svi gube isti udio ukupne korisnosti) i jednaka granična žrtva (marginalna žrtva treba biti jednaka za sve). Upravo posljednja varijanta vodi do zaključka da je optimalno progresivno oporezivanje, jer se redistribucijom dohotka izjednačavaju granične korisnosti među pojedincima (musgrave1989?). Međutim, suvremena teorija naglašava kompromis: iako progresivnost povećava pravednost, ona može stvoriti distorzije u ponašanju (npr. smanjiti radne poticaje), pa optimalna razina progresivnosti ovisi o ravnoteži između efikasnosti i jednakosti (saez2001?).
Lafferova krivulja — iako nije dio formalne teorije optimalnog oporezivanja u užem smislu, Lafferova krivulja često se koristi kao intuitivni alat za razumijevanje odnosa između poreznih stopa i poreznih prihoda.


Prikaži kod
viewof laffer_controls = Inputs.form({
  eps_T: Inputs.range([0.1, 2.5], {value: 0.5, step: 0.05, label: "Elastičnost porezne osnovice ε:"}),
  t_now: Inputs.range([0, 95],    {value: 35,  step: 1,    label: "Trenutna porezna stopa t (%):"})
})









Prikaži kod
eps_T = laffer_controls.eps_T









Prikaži kod
t_now = laffer_controls.t_now









Prikaži kod
{
  // Simple Laffer model:
  // Tax base shrinks with the rate via a constant-elasticity response:
  // B(t) = B0 · (1 − t)^ε    (where ε is the elasticity of the tax base w.r.t. the net-of-tax rate).
  // Revenue:   R(t) = t · B(t) = t · B0 · (1 − t)^ε.
  // Revenue-maximising rate: dR/dt = 0  ⇒  t* = 1 / (1 + ε).
  const B0 = 100;
  const eps = eps_T;

  const tStar = 1 / (1 + eps);                         // revenue-maximising rate
  const Rmax  = tStar * B0 * Math.pow(1 - tStar, eps); // peak revenue

  const ts = d3.range(0, 0.99, 0.005);
  const curve = ts.map(t =&gt; ({t: t * 100, R: t * B0 * Math.pow(1 - t, eps)}));

  // Reader's current point
  const tCur = t_now / 100;
  const Rcur = tCur * B0 * Math.pow(Math.max(0, 1 - tCur), eps);
  const onRising = tCur &lt; tStar;

  const Rceil = Math.max(Rmax * 1.10, 25);

  return Plot.plot({
    width: 760,
    height: 500,
    marginLeft: 65,
    marginBottom: 55,
    style: {fontSize: "12px", fontFamily: "Roboto, system-ui, sans-serif", color: "#4A5568"},
    x: {label: "Porezna stopa t (%) →", domain: [0, 100], grid: false},
    y: {label: "↑ Porezni prihodi R",   domain: [0, Rceil], grid: true},
    marks: [
      Plot.ruleY([0], {stroke: "#CBD5E0"}),

      // Laffer curve
      Plot.line(curve, {x: "t", y: "R", stroke: "#1f77b4", strokeWidth: 2.5}),

      // Area under curve, faded
      Plot.areaY(curve, {x: "t", y: "R", fill: "#BEE3F8", fillOpacity: 0.25}),

      // Revenue-maximising rate: vertical dashed line + dot
      Plot.ruleX([tStar * 100], {y1: 0, y2: Rmax, stroke: "#4A5568", strokeDasharray: "4,3"}),
      Plot.dot([{t: tStar * 100, R: Rmax}],
        {x: "t", y: "R", r: 6, fill: "#2D3748", stroke: "white", strokeWidth: 2}),

      // Reader's current point
      Plot.ruleX([tCur * 100], {y1: 0, y2: Rcur,
        stroke: onRising ? "#2ca02c" : "#C53030", strokeDasharray: "2,2"}),
      Plot.ruleY([Rcur], {x1: 0, x2: tCur * 100,
        stroke: onRising ? "#2ca02c" : "#C53030", strokeDasharray: "2,2"}),
      Plot.dot([{t: tCur * 100, R: Rcur}],
        {x: "t", y: "R", r: 7,
         fill: onRising ? "#2ca02c" : "#C53030", stroke: "white", strokeWidth: 2}),

      // Labels
      Plot.text([{t: tStar * 100, R: Rmax, label: `Vrh prihoda  t* = ${(tStar * 100).toFixed(0)} %`}],
        {x: "t", y: "R", text: "label", textAnchor: "middle", dy: -14,
         fontSize: 13, fill: "#2D3748", fontWeight: 700}),

      Plot.text([{t: tCur * 100, R: Rcur,
         label: onRising ? "Rastući dio" : "Padajući dio (previsoka stopa)"}],
        {x: "t", y: "R", text: "label",
         textAnchor: tCur * 100 &gt; 60 ? "end" : "start",
         dx: tCur * 100 &gt; 60 ? -10 : 10, dy: 16,
         fontSize: 12, fill: onRising ? "#2ca02c" : "#C53030", fontWeight: 700}),

      // Top readouts
      Plot.text([{x: 2, y: Rceil * 0.97,
         label: `Trenutna stopa: ${t_now} %   |   Prihod: ${Rcur.toFixed(1)}   |   Vrh: ${Rmax.toFixed(1)} pri ${(tStar * 100).toFixed(0)} %`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 13, fill: "#2D3748", fontWeight: 700}),
      Plot.text([{x: 2, y: Rceil * 0.91,
         label: `Iskorištenost: ${(Rcur / Rmax * 100).toFixed(0)} % od maksimalnog prihoda`}],
        {x: "x", y: "y", text: "label", textAnchor: "start",
         fontSize: 12, fill: "#4A5568", fontWeight: 500})
    ]
  });
}







Kako čitati graf. Plava krivulja je Lafferova krivulja: porezni prihod kao funkcija stope. Crna točka označava vrh prihoda (t*) — stopu pri kojoj država ostvaruje najveći mogući prihod. Točka koja se kreće s vašim klizačem zelena je ako se nalazite na rastućem dijelu krivulje (dizanje stope povećava prihod) ili crvena ako ste na padajućem dijelu (dizanje stope smanjuje prihod jer porezna osnovica reagira jače nego što stopa raste).
Ključni rezultat. Pri konstantnoj elastičnosti porezne osnovice ε, vrh se nalazi pri t* = 1 / (1 + ε). Ova jednostavna formula objašnjava cijelu raspravu o Lafferovoj krivulji: ne postoji „univerzalni” Lafferov vrh — njegova lokacija ovisi isključivo o tome koliko porezna osnovica reagira na promjene stope.
Što isprobati. (1) Pri ε = 0,2 (neelastična osnovica, npr. radnici s ograničenim alternativama, tržišta s malo evazije): vrh je na t* ≈ 83 %. Sve realistične stope nalaze se na rastućem dijelu. (2) Pri ε = 0,5 (umjerena reakcija — empirijski najčešća procjena za rad u razvijenim zemljama): vrh je na t* ≈ 67 %. Stope iznad 65–70 % postaju kontraproduktivne. (3) Pri ε = 1,5 (visoka elastičnost — npr. dohodak najbogatijih, internacionalno mobilan kapital, tržišta s razvijenom evazijom): vrh pada na t* ≈ 40 %. Visoke marginalne stope na takve osnovice mogu zapravo smanjiti prihode. Praktična poruka. Politička debata o tome je li određena zemlja „prešla Lafferov vrh” jest, na kraju krajeva, debata o empirijskoj veličini ε — koja se razlikuje među zemljama, među vrstama poreza, pa čak i među dohodovnim skupinama. Lafferova krivulja nije politički argument, nego okvir za tu debatu.
Ovaj koncept pokazuje da porezni prihodi ne rastu linearno s poreznom stopom. Pri vrlo visokim stopama dolazi do smanjenja ekonomske aktivnosti i porezne osnovice, što može smanjiti ukupne prihode. Njegova ključna poruka uklapa se u teoriju optimalnog oporezivanja: ponašanje poreznih obveznika ključno je za dizajn porezne politike.
